class Solution(object):
    def largestInteger(self, nums, k):
        n = len(nums)
        from collections import defaultdict
        cnt = defaultdict(int)
        for l in range(n - k + 1):
            for v in set(nums[l:l + k]):
                cnt[v] += 1
        result = -1
        for v, c in cnt.items():
            if c == 1:
                result = max(result, v)
        return result
